title:
以下代码的输出结果是什么？
```javascript
const obj = {
  name: 'Alice',
  sayHi: () => {
    console.log(this.name);
  }
};
obj.sayHi();
```

以下代码的输出结果是什么？
```javascript
function foo() {
  console.log(this.a);
}
var a = 2;
foo.call(null);
```

以下代码的输出结果是什么？
```javascript
var a = 10;
function test() {
  console.log(a);
  var a = 20;
  console.log(a);
}
test();
```

以下代码的输出结果是什么？
```javascript
for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100);
}
```

以下代码的输出结果是什么？
```javascript
function createCounter() {
  let count = 0;
  return function() {
    return ++count;
  };
}
const counter = createCounter();
console.log(counter());
console.log(counter());
```

以下代码的输出结果是什么？
```javascript
function Person(name) {
  this.name = name;
}
Person.prototype.sayName = function() {
  console.log(this.name);
};
const p = new Person('Bob');
console.log(p.__proto__ === Person.prototype);
```

以下代码的输出结果是什么？
```javascript
function Animal() {}
function Dog() {}
Dog.prototype = new Animal();
const dog = new Dog();
console.log(dog.__proto__ === Dog.prototype);
console.log(Dog.prototype.__proto__ === Animal.prototype);
```

以下代码的输出结果是什么？
```javascript
class A {}
class B extends A {}
const b = new B();
console.log(b.__proto__.__proto__ === A.prototype);
```

以下代码的输出结果是什么？
```javascript
const promise = new Promise((resolve, reject) => {
  console.log(1);
  resolve();
  console.log(2);
});
promise.then(() => console.log(3));
console.log(4);
```

以下代码的输出结果是什么？
```javascript
async function foo() {
  console.log('A');
  await Promise.resolve();
  console.log('B');
}
foo();
console.log('C');
```

以下代码的输出结果是什么？
```javascript
console.log(1);
setTimeout(() => console.log(2), 0);
Promise.resolve().then(() => console.log(3));
console.log(4);
```

以下代码的输出结果是什么？
```javascript
setTimeout(() => console.log('timeout'), 0);
Promise.resolve().then(() => console.log('promise'));
process.nextTick(() => console.log('nextTick'));
```

